import React from 'react';
import { useNavigate } from 'react-router-dom';
import './Home.css';

export default function Home() {
  const navigate = useNavigate();

  return (
    <div className="container">
      <header className="header">
        <div className="logo">LogoRéservation</div>
        <nav>
          <button onClick={() => navigate('/login')}>Connexion</button>
          <button onClick={() => navigate('/register')}>Inscription</button>
          <button className="primary" onClick={() => navigate('/reservation')}>Nouvelle Réservation</button>
        </nav>
      </header>
      <main className="main">
        <h2>Bienvenue sur l'application de réservation</h2>
        <p>Réservez votre salle de réunion en toute simplicité.</p>
      </main>
    </div>
  );
}
